import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Team {
  rank: number;
  team: string;
  wins: number;
  losses: number;
  points: number;
}

interface LeagueData {
  league: string;
  season: string;
  topTeams: Team[];
}

export default function Widget() {
  const data = response.data as LeagueData;
  const { league, season, topTeams } = data;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1C1C1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" color="#FF5733" fontWeight={600}>
              {league} Standings
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Season: {season}
            </Typography>
          </Box>

          <Stack spacing={1}>
            {topTeams.map((team) => (
              <Box key={team.rank} sx={{ bgcolor: '#2C2C2E', borderRadius: 1, p: 1 }}>
                <Stack direction="row" justifyContent="space-between" alignItems="center">
                  <Box>
                    <Typography variant="body2" color="text.primary" fontWeight={500}>
                      {team.rank}. {team.team}
                    </Typography>
                    <Typography variant="caption" color="text.secondary">
                      Wins: {team.wins} | Losses: {team.losses}
                    </Typography>
                  </Box>
                  <Chip label={`${team.points} pts`} sx={{ bgcolor: '#C70039', color: '#fff', fontWeight: 600 }} />
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
